class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        int n = s.size();
        int res = 0;
        int cur = 0;
        unordered_map<char, int> mp;
        for (int i = 0; i < chars.size(); i++) {
            mp[chars[i]] = vals[i];
        }
        for (int i = 0; i < n; i++) {
            int val = mp[s[i]] ? mp[s[i]] : s[i] - 'a' + 1;
            cur = max(0, cur + val);
            res = max(res, cur);
            cur = max(0, cur - val);
        }
        return res;
    }
};
